/**
 * Lightweight JSON Schema Validator
 * Supports: type, required, min/max, minLength/maxLength, pattern, enum, nested objects, array items
 */
class JsonSchemaValidator {
  /**
   * Validates data against a JSON Schema
   * @param {any} data - The data to validate
   * @param {Object} schema - The JSON Schema definition
   * @param {string} path - Internal tracking for error paths
   * @returns {{ valid: boolean, errors: string[] }} Validation result
   */
  validate(data, schema, path = 'root') {
    const errors = [];

    // 1. Type Validation
    if (schema.type && !this._checkType(data, schema.type)) {
      errors.push(`${path}: expected type "${schema.type}"`);
      // Fail fast on type mismatch to avoid cascading false errors
      return { valid: false, errors };
    }

    // 2. Enum Validation
    if (schema.enum !== undefined) {
      if (!schema.enum.some(item => this._deepEqual(item, data))) {
        errors.push(`${path}: value must be one of [${JSON.stringify(schema.enum)}]`);
      }
    }

    // 3. Number/Integer Constraints
    if (typeof data === 'number' && !Number.isNaN(data)) {
      if (schema.minimum !== undefined && data < schema.minimum) {
        errors.push(`${path}: must be >= ${schema.minimum}`);
      }
      if (schema.maximum !== undefined && data > schema.maximum) {
        errors.push(`${path}: must be <= ${schema.maximum}`);
      }
    }

    // 4. String Constraints
    if (typeof data === 'string') {
      if (schema.minLength !== undefined && data.length < schema.minLength) {
        errors.push(`${path}: length must be >= ${schema.minLength}`);
      }
      if (schema.maxLength !== undefined && data.length > schema.maxLength) {
        errors.push(`${path}: length must be <= ${schema.maxLength}`);
      }
      if (schema.pattern !== undefined) {
        try {
          if (!new RegExp(schema.pattern).test(data)) {
            errors.push(`${path}: must match pattern "${schema.pattern}"`);
          }
        } catch (e) {
          errors.push(`${path}: invalid regex pattern "${schema.pattern}"`);
        }
      }
    }

    // 5. Object Validation (Nested Objects & Required Fields)
    if (this._checkType(data, 'object')) {
      if (Array.isArray(schema.required)) {
        for (const field of schema.required) {
          if (!(field in data)) {
            errors.push(`${path}.${field}: required field is missing`);
          }
        }
      }

      if (schema.properties && typeof schema.properties === 'object') {
        for (const [key, propSchema] of Object.entries(schema.properties)) {
          if (key in data) {
            const result = this.validate(data[key], propSchema, `${path}.${key}`);
            errors.push(...result.errors);
          }
        }
      }
    }

    // 6. Array Validation (Items)
    if (this._checkType(data, 'array')) {
      if (schema.items && typeof schema.items === 'object') {
        data.forEach((item, index) => {
          const result = this.validate(item, schema.items, `${path}[${index}]`);
          errors.push(...result.errors);
        });
      }
    }

    return { valid: errors.length === 0, errors };
  }

  /**
   * Maps JSON Schema types to JavaScript type checks
   */
  _checkType(value, type) {
    switch (type) {
      case 'string':  return typeof value === 'string';
      case 'number':  return typeof value === 'number' && !Number.isNaN(value);
      case 'integer': return typeof value === 'number' && Number.isInteger(value);
      case 'boolean': return typeof value === 'boolean';
      case 'array':   return Array.isArray(value);
      case 'object':  return typeof value === 'object' && value !== null && !Array.isArray(value);
      case 'null':    return value === null;
      default:        return false;
    }
  }

  /**
   * Deep equality check for enum validation
   */
  _deepEqual(a, b) {
    if (a === b) return true;
    if (a == null || b == null) return false;
    if (typeof a !== typeof b) return false;

    if (Array.isArray(a)) {
      if (!Array.isArray(b) || a.length !== b.length) return false;
      return a.every((val, i) => this._deepEqual(val, b[i]));
    }

    if (typeof a === 'object') {
      const keysA = Object.keys(a);
      const keysB = Object.keys(b);
      if (keysA.length !== keysB.length) return false;
      return keysA.every(key => this._deepEqual(a[key], b[key]));
    }

    return false;
  }
}

// Export for Node.js or use directly in browser
if (typeof module !== 'undefined' && module.exports) {
  module.exports = JsonSchemaValidator;
}
